class Dog:
    def __init__(self, name):
        self.name = name

    def bark(self):
        print(self.name, "says Woof!")

my_dog = Dog("Rex")
my_dog.bark()

class Dog:
    def __init__(self, name, age):
        self.name = name
        self.age = age

    def bark(self):
        print(self.name, "says Woof! I am", self.age, "years old.")

dog1 = Dog("Rex", 3)
dog2 = Dog("Bella", 5)
dog1.bark()
dog2.bark()
